#!/usr/bin/env python3
"""Add bio_en fields to scholars missing them - Batch 2 (ids 121-200)."""
import json
import os

SCHOLARS_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'scholars.json')

BIOS = {
    121: "Nafi mawla ibn Umar (d. 735 CE) was a freed slave of the companion Abdullah ibn Umar and one of the most important hadith transmitters in Islamic history. He served Abdullah ibn Umar for approximately thirty years, during which time he memorized a vast body of hadith and observed the Prophet's Sunnah as practiced by Ibn Umar, who was known as the most meticulous follower of prophetic practices.\n\nNafi's transmission from Ibn Umar, and Imam Malik's transmission from Nafi, created what hadith scholars call the 'Golden Chain' (silsilat adh-dhahab): Malik from Nafi from Ibn Umar from the Prophet. This chain was considered by scholars like al-Bukhari to be the most authentic chain of transmission in all of hadith literature.\n\nNafi also transmitted hadith from other companions and Tabiin, and his students included not only Malik but also al-Layth ibn Sad, Ayyub as-Sakhtiyani, and many other prominent scholars. His narrations appear in all six canonical hadith collections. He died in Medina, leaving behind a legacy as one of the most crucial links in the preservation of prophetic knowledge.",

    122: "Ibn Ishaq (704-768 CE), fully Muhammad ibn Ishaq ibn Yasar, was the author of the earliest comprehensive biography of Prophet Muhammad, a work that became the foundation of the seerah (prophetic biography) genre. Born in Medina, he collected oral traditions about the Prophet's life from scholars across the Muslim world.\n\nIbn Ishaq compiled his biography in three parts: al-Mubtada (the beginning, covering pre-Islamic history), al-Mabath (the mission, covering the Prophet's life in Mecca), and al-Maghazi (the military campaigns). Although his original work has not survived in its entirety, it was preserved through the edited version of Ibn Hisham, known as as-Sirah an-Nabawiyyah, which remains one of the most widely read Islamic texts.\n\nSome hadith scholars, including Malik ibn Anas, criticized certain aspects of Ibn Ishaq's methodology, particularly regarding his inclusion of Israelite reports and poetry of questionable authenticity. However, others like az-Zuhri and Sufyan ibn Uyaynah praised his knowledge. His work remains indispensable for understanding the Prophet's life and the early Muslim community, and virtually all subsequent seerah works draw upon it.",

    123: "Al-Awzai (707-774 CE), fully Abdurrahman ibn Amr al-Awzai, was the leading scholar of the Levant (Syria-Palestine) and the founder of a school of jurisprudence that was dominant in Syria, al-Andalus, and North Africa before being gradually replaced by the Maliki and Shafii schools. He was born in Baalbek, Lebanon, and settled in Beirut.\n\nAl-Awzai's legal methodology relied heavily on the living practice (amal) of the Muslim community, particularly the traditions of the Companions who had settled in Syria. He was a contemporary of Abu Hanifah and Malik and engaged in scholarly debates with both. His school was particularly strong in matters of jihad, international law, and the treatment of non-Muslim subjects.\n\nHe was known for his piety, his independence from political authority, and his courage in confronting unjust rulers. When the Abbasid caliph's uncle threatened him, al-Awzai stood his ground and spoke the truth. He advocated for the protection of Christians in Lebanon and opposed their forced displacement. He died in Beirut, where he is buried, and his school of jurisprudence continued in al-Andalus until the tenth century before being absorbed into the Maliki and Shafii traditions.",

    124: "Malik ibn Anas (711-795 CE) was the founder of the Maliki school of jurisprudence and one of the most revered scholars in Islamic history. Known as the Imam of Dar al-Hijrah (the Imam of the Abode of Migration, i.e., Medina), he spent his entire life in the Prophet's city, which deeply shaped his legal methodology.\n\nMalik authored al-Muwatta, one of the earliest compilations of hadith and Islamic jurisprudence. The work combines prophetic hadith with the legal opinions of the companions and the established practice of the people of Medina, which Malik considered a form of transmitted Sunnah. He studied under hundreds of scholars, including Nafi mawla ibn Umar, Ibn Shihab az-Zuhri, and Rabiah ar-Rai.\n\nMalik's methodology gave special weight to the practice of Medina (amal ahl al-Madinah) as a source of law, arguing that the unbroken practice of the Prophet's city constituted a reliable transmission of the Sunnah. He was known for his extreme caution in issuing fatwas and in narrating hadith. He was physically punished for a fatwa that displeased the governor but never retracted it. The Maliki school spread throughout North Africa, West Africa, al-Andalus, and parts of the Arabian Peninsula, where it remains dominant today.",

    125: "Imam Malik ibn Anas (711-795 CE) was the founder of the Maliki school of jurisprudence and author of al-Muwatta, one of the earliest compilations of hadith and fiqh. Known as the Imam of Dar al-Hijrah, he never left Medina and considered the continuous practice of its people to be a source of law alongside the Quran and Sunnah.\n\nMalik was the teacher of scholars who would shape Islamic thought for centuries, including Muhammad ibn Idris ash-Shafii, who studied under him for years, and Muhammad ash-Shaybani, the Hanafi codifier. His scholarly circle in the Prophet's Mosque attracted students from across the Muslim world, and his legal opinions were sought by caliphs and governors alike.\n\nHis approach to jurisprudence was conservative and practical, preferring established Medinan practice over isolated reports. He was known for saying 'I do not know' to questions he was uncertain about, considering this a sign of scholarly integrity rather than weakness. The Maliki school that bears his name is today followed by the majority of Muslims in North and West Africa, and has adherents across the Muslim world.",

    126: "Al-Layth ibn Sad (713-791 CE) was the leading scholar of Egypt in his time and one of the most respected jurists of the classical period. Imam ash-Shafii once said, 'Al-Layth was more knowledgeable in fiqh than Malik, but his students did not serve him well,' meaning they failed to systematize and transmit his legal opinions as effectively as Malik's students did.\n\nAl-Layth was born in Qarqashandah, Egypt, and became the chief scholar, mufti, and wealthy philanthropist of Egypt. His annual income was reported to be around 80,000 dinars, all of which he would spend in charity before the end of the year. He would regularly send gifts to Malik ibn Anas in Medina, demonstrating his generosity even toward scholars in other regions.\n\nAlthough al-Layth developed a complete school of jurisprudence and even engaged in scholarly correspondence with Malik about their methodological differences, his school did not survive because his students failed to codify his opinions as systematically as the students of Abu Hanifah and Malik did. His loss to Islamic jurisprudence is considered one of the great missed opportunities of the classical period.",

    127: "Layth ibn Sa'd (713-791 CE) was the greatest scholar of Egypt in his era and a figure whom Imam ash-Shafii considered more knowledgeable than Malik in fiqh. He was enormously wealthy from his agricultural estates and legendarily generous, reportedly spending his entire annual income of 80,000 dinars in charity.\n\nLayth's school of fiqh was well-developed and sophisticated, drawing on both the Medinan and Iraqi traditions while incorporating the specific needs of Egyptian society. He engaged in a famous scholarly exchange of letters with Imam Malik, respectfully disagreeing with Malik's methodology of privileging the practice of the people of Medina over authenticated hadith from other regions.\n\nDespite his scholarly brilliance and his complete legal methodology, his school did not survive because he lacked students who could systematically record and transmit his opinions to future generations. This stands as a historical lesson about the importance of codification in the survival of intellectual traditions. He died in Cairo and is buried there, remembered as one of the great could-have-beens of Islamic legal history.",

    128: "Sufyan ath-Thawri (716-778 CE) was one of the greatest hadith scholars and jurists of the second Islamic century, bearing the title Amir al-Muminin fil-Hadith (Commander of the Believers in Hadith). Born in Kufa, he studied under over 600 scholars and became the foremost authority on hadith in the Iraqi school.\n\nSufyan developed his own school of jurisprudence that combined elements of the Kufan tradition with his mastery of hadith. His approach gave primacy to authentic hadith over analogical reasoning. He compiled an early hadith collection called al-Jami and authored works on legal theory. His school was followed for a time but eventually merged into the Hanafi tradition.\n\nHe was known for his extreme piety, his weeping during prayer and hadith narration, and his fierce independence from political power. He refused appointments from the Abbasid caliphs and spent periods of his life in hiding from their agents. Ahmad ibn Hanbal said, 'I do not know anyone more knowledgeable than Sufyan.' He died in Basra while still evading political authority, and his legacy endures through his hadith narrations, which appear extensively in all the major collections.",

    129: "Sufyan ibn Uyaynah (725-814 CE) was a leading hadith scholar based in Mecca and one of the most important teachers of the classical period. Born in Kufa, he moved to Mecca at a young age and spent most of his life there, becoming the preeminent scholar of the Holy City.\n\nSufyan ibn Uyaynah was considered one of the most reliable narrators of hadith, and his narrations form a significant portion of the content of the six canonical collections. He studied under major Tabiin including az-Zuhri and Amr ibn Dinar, and his students included some of the greatest scholars in Islamic history: ash-Shafii, Ahmad ibn Hanbal, Yahya ibn Main, and Ali ibn al-Madini.\n\nHe was known for his exceptional memory and his ability to recall hadith with precision even in his old age. He was also renowned for his tafsir knowledge and would frequently explain Quranic verses using hadith. He lived to approximately ninety years and his teaching circle in the Haram of Mecca was one of the most sought-after scholarly gatherings of his time.",

    130: "Al-Fudayl ibn Iyad (725-803 CE) was a renowned ascetic and hadith transmitter whose dramatic spiritual transformation made him one of the most celebrated figures in the history of Islamic piety. According to tradition, he was a highway robber in Khurasan before a profound spiritual experience, reportedly triggered by hearing a Quranic verse, led him to repent and dedicate his life entirely to the worship of Allah.\n\nAfter his repentance, al-Fudayl traveled to Mecca where he became one of the most revered spiritual authorities of his age. He studied hadith and transmitted narrations that appear in the major collections. His spiritual counsel was sought by the most powerful rulers of his time, and the famous story of his encounter with the Abbasid caliph Harun ar-Rashid, in which he reduced the caliph to tears, is one of the most retold stories in Islamic literature.\n\nAl-Fudayl's sayings on sincerity, renunciation of the world, and fear of Allah became foundational texts in the literature of Islamic spirituality. He said, 'If I were offered the whole world, I would consider it too insignificant to want it.' He died in Mecca and is remembered as an exemplar of the transformative power of sincere repentance.",

    131: "Abu Yusuf (731-798 CE), born Yaqub ibn Ibrahim, was the most prominent student of Abu Hanifah and the first person in Islamic history to hold the position of Qadi al-Qudat (Chief Justice), a role he filled under three Abbasid caliphs: al-Mahdi, al-Hadi, and Harun ar-Rashid.\n\nAbu Yusuf studied under Abu Hanifah for approximately seventeen years and also studied hadith under scholars like al-Awzai and Malik ibn Anas, which gave him a broader perspective than strict adherence to the Kufan tradition. His Kitab al-Kharaj (Book of Taxation) was written at the request of Harun ar-Rashid and became the foundational text of Islamic public finance and taxation law.\n\nAs Chief Justice, Abu Yusuf was responsible for appointing judges across the Abbasid Empire, and he used this position to spread the Hanafi school of law throughout the Muslim world. His legal opinions sometimes differed from those of his teacher Abu Hanifah, and in the Hanafi tradition, the opinions of Abu Yusuf carry special weight. He is considered one of the primary architects of the Hanafi school as a practical legal system.",

    132: "Abdullah ibn al-Mubarak (736-797 CE) was a polymath scholar of Merv (in modern Turkmenistan) who excelled simultaneously in hadith, fiqh, asceticism, and military service. He was praised by his contemporaries as 'the scholar of the East' and was considered one of the most complete scholars of his generation.\n\nIbn al-Mubarak traveled extensively in search of knowledge, studying under hundreds of scholars across the Muslim world, including Abu Hanifah, Malik, Sufyan ath-Thawri, and al-Awzai. He authored some of the earliest hadith compilations, including Kitab az-Zuhd (Book of Asceticism) and Kitab al-Jihad (Book of Jihad), both of which are preserved and studied to this day.\n\nHe was also a wealthy merchant who donated generously to scholars and the poor. He would regularly participate in military campaigns on the frontiers of the Muslim world. Ahmad ibn Hanbal said, 'In the time of Ibn al-Mubarak, there was no one more devoted to seeking knowledge than him.' He died at Hit, Iraq, while returning from a military campaign, and his funeral was attended by vast crowds.",

    133: "Yahya ibn Sa'id al-Qattan (738-813 CE) was one of the founding fathers of hadith criticism (ilm ar-rijal), the science of evaluating the reliability of hadith narrators. Based in Basra, he established rigorous standards for accepting and rejecting narrators that shaped the methodology of all subsequent hadith scholarship.\n\nAl-Qattan was extremely strict in his evaluation of narrators, and his judgments were considered authoritative by the great hadith scholars who came after him. Ahmad ibn Hanbal considered him the most knowledgeable person in hadith criticism of his time. His pronouncements on the reliability of individual narrators became foundational reference points for later critics.\n\nHe was known for his exceptional memory and his ability to identify subtle flaws in hadith chains. Despite his strictness in scholarly matters, he was known for his personal humility and piety. He would weep profusely during prayer and was deeply feared by narrators who knew that his critical judgment could determine whether their hadith would be accepted or rejected by future generations.",

    134: "Waki ibn al-Jarrah (746-812 CE) was a leading hadith scholar from Kufa who served as one of the primary teachers of both Ahmad ibn Hanbal and Muhammad ibn Idris ash-Shafii. He was known for his prodigious memory, his piety, and his mastery of hadith.\n\nWaki studied under Sufyan ath-Thawri, al-Awzai, and many other scholars of his time. He compiled hadith collections and his narrations are found throughout the six canonical collections. Ahmad ibn Hanbal said of him, 'I have never seen anyone who memorized hadith better than Waki.' Ash-Shafii similarly praised him, saying he had not seen anyone with a better memory.\n\nWaki was known for connecting strong memory with sincere piety. When ash-Shafii asked him for advice on memorization, Waki told him to abandon sins, for knowledge is a light from Allah and Allah's light is not given to a sinner. He died near Medina while returning from Hajj and is remembered as one of the great transmitters of the Kufan hadith tradition.",

    135: "Muhammad ibn al-Hasan ash-Shaybani (749-805 CE) was one of the most important jurists in Islamic history and the principal codifier of the Hanafi school of jurisprudence. He studied under Abu Hanifah as a young man and continued his education under Abu Yusuf, Imam Malik in Medina, and other leading scholars.\n\nAsh-Shaybani authored the six foundational texts of Hanafi jurisprudence known as Zahir ar-Riwayah (the Manifest Narrations): al-Mabsut, az-Ziyadat, al-Jami as-Saghir, al-Jami al-Kabir, as-Siyar as-Saghir, and as-Siyar al-Kabir. These works systematically recorded the legal opinions of Abu Hanifah, Abu Yusuf, and ash-Shaybani himself, providing the Hanafi school with the comprehensive written foundation it needed to endure.\n\nAsh-Shaybani also studied under Imam Malik and transmitted al-Muwatta, and his version of the text remains one of the important recensions. He served as a judge under Harun ar-Rashid and was the teacher of Imam ash-Shafii, who studied fiqh under him. He died in Ray (near modern Tehran) and is remembered as the scholar whose codification efforts ensured the survival and dominance of the Hanafi school.",

    136: "Abdurrahman ibn Mahdi (752-813 CE) was one of the leading hadith critics and scholars of Basra, renowned for his mastery of hadith science and his strict standards for narrator evaluation. He was a key teacher of Ahmad ibn Hanbal and played a pivotal role in developing the methodology of hadith criticism.\n\nIbn Mahdi studied under Sufyan ath-Thawri, Malik ibn Anas, and other major scholars. He was considered the peer of Yahya ibn Said al-Qattan in hadith criticism, and the two of them set the standards that later scholars would follow. Ahmad ibn Hanbal called him 'the most knowledgeable of people in hadith.'\n\nHe was known for a famous statement addressed to Imam ash-Shafii: 'When I want to know the truth of a matter, I look at what Malik says, and what Abdurrahman ibn Mahdi says, for they are the two most knowledgeable people of their time.' His judgments on narrator reliability are foundational references in the biographical dictionaries of hadith scholars. He died in Basra and is remembered as one of the architects of hadith criticism methodology.",

    137: "Muhammad ibn Idris ash-Shafii (767-820 CE) was the founder of the Shafii school of jurisprudence and the father of Islamic legal theory (usul al-fiqh). Born in Gaza, Palestine, he memorized the Quran by age seven and al-Muwatta of Malik by age ten. He studied under Imam Malik in Medina and Muhammad ash-Shaybani in Baghdad.\n\nAsh-Shafii's revolutionary contribution was his systematic articulation of legal methodology in his book ar-Risalah, the first work ever written on usul al-fiqh. He established the hierarchy of legal sources (Quran, Sunnah, ijma, qiyas) and developed rigorous principles for deriving rulings from these sources. His methodology provided a common framework that all subsequent scholars, regardless of their school, would engage with.\n\nAsh-Shafii uniquely bridged the Medinan and Iraqi schools of jurisprudence, having studied deeply in both traditions. He developed two versions of his madhab: the 'old school' (al-qadim) formulated in Baghdad and the 'new school' (al-jadid) revised after his move to Egypt. He died in Cairo and is buried there. The Shafii school is followed today in East Africa, Southeast Asia, Yemen, southern Egypt, and the Kurdish regions.",

    138: "Al-Khalil ibn Ahmad al-Farahidi (718-786 CE) was an Arab polymath from Oman who made foundational contributions to multiple fields of Arabic learning. He is best known as the inventor of Arabic prosody (ilm al-arud), the system for analyzing Arabic poetic meters, which he developed by studying the rhythmic patterns of Arabic poetry.\n\nAl-Khalil also compiled Kitab al-Ayn, considered the first comprehensive dictionary of the Arabic language. His innovative approach organized words not alphabetically but by their points of articulation, starting with the deepest sounds in the throat. Although this arrangement made the dictionary difficult to use, its systematic approach to cataloging the Arabic lexicon was unprecedented.\n\nHe was the teacher of Sibawaih, the author of al-Kitab, the foundational work of Arabic grammar. Through Sibawaih, al-Khalil's grammatical insights became the basis of the Basran school of Arabic grammar. Despite his towering intellectual achievements, al-Khalil lived in extreme poverty, refusing patronage from rulers. He died in Basra, reportedly from walking into a pillar while deep in thought about a grammatical problem.",

    139: "Jabir ibn Hayyan (c. 721-815 CE) was a Muslim polymath often regarded as the father of chemistry. Known in the medieval West as Geber, he introduced experimental methodology and systematic classification into the study of substances, moving beyond the speculative approaches of earlier alchemists.\n\nJabir is credited with the discovery or refinement of many important chemical processes, including distillation, crystallization, evaporation, and filtration. He developed equipment such as the alembic (al-inbiq) for distillation that would be used for centuries. His systematic approach to experimentation, involving careful observation and documentation of results, laid the groundwork for the modern scientific method.\n\nHis corpus of writings, known as the Jabirian corpus, covers chemistry, medicine, pharmacology, astronomy, and philosophy. While scholars debate which works were authored by Jabir himself and which by later writers working in his tradition, the overall contribution to the development of chemistry is beyond question. The English word 'gibberish' is sometimes traced to the perceived impenetrability of his alchemical writings.",

    140: "Abdullah ibn al-Mubarak (736-797 CE) was a versatile scholar of Merv in Khurasan who excelled in hadith science, fiqh, asceticism (zuhd), and military service, a rare combination that earned him universal respect across the Muslim world. He was called the Commander of the Believers in Hadith by his contemporaries.\n\nIbn al-Mubarak traveled across the Islamic world in search of knowledge, studying under Abu Hanifah, Malik, Sufyan ath-Thawri, and hundreds of other scholars. He authored pioneering works including Kitab az-Zuhd and Kitab al-Jihad. His hadith narrations are found in all six canonical collections, and he was considered one of the most reliable and knowledgeable transmitters of his generation.\n\nDespite being a wealthy merchant, he lived simply and donated his profits to scholars, students, and the poor. He regularly participated in frontier military campaigns, combining the life of a scholar with that of a mujahid. Ahmad ibn Hanbal described him as one of the most complete individuals of his era. He died while returning from a military expedition and is buried at Hit, Iraq.",

    141: "Abd ar-Razzaq as-Sanani (744-827 CE) was a hadith scholar from Sana'a, Yemen, who compiled one of the most important early hadith collections: al-Musannaf. This massive work, organized by legal topics, preserves hadith, companion opinions, and Tabiin rulings that might otherwise have been lost.\n\nAbd ar-Razzaq studied under major scholars including Maamar ibn Rashid (a student of az-Zuhri), Sufyan ath-Thawri, and Ibn Jurayj. Scholars from across the Muslim world traveled to Yemen specifically to study with him, including Ahmad ibn Hanbal, Yahya ibn Main, and Ali ibn al-Madini. His al-Musannaf is considered an invaluable source for understanding early Islamic legal thought.\n\nHe also compiled a tafsir work that preserves early Quranic commentary traditions. In his later years, he lost his eyesight, and some scholars expressed caution about narrations transmitted from him during this period. Despite this, his overall contribution to hadith preservation is immense, and his al-Musannaf remains one of the most studied early hadith compilations.",

    142: "Muhammad ibn al-Hasan ash-Shaybani (750-805 CE) was a principal student of Abu Hanifah who codified Hanafi jurisprudence in six foundational texts known as Zahir ar-Riwayah. He also studied under Imam Malik in Medina, giving him a broad perspective that enriched his legal reasoning.\n\nHis six major works provided the Hanafi school with a systematic, written legal corpus that ensured its preservation and transmission. These books recorded the legal opinions of Abu Hanifah, Abu Yusuf, and ash-Shaybani himself in a structured format that could be taught and studied. Without this codification effort, the Hanafi school might have gradually disappeared like other early schools of law.\n\nAsh-Shaybani was also a teacher of Imam ash-Shafii, who credited him with much of his knowledge of Iraqi jurisprudence. He served as a judge appointed by Harun ar-Rashid and was known for his sharp legal mind and his ability to synthesize different legal traditions. He died in Ray (modern Tehran) and is regarded as one of the three principal architects of the Hanafi school.",

    143: "Sibawaih (c. 760-796 CE) was a Persian scholar who authored al-Kitab (The Book), the first comprehensive and systematic grammar of the Arabic language. Despite Arabic not being his mother tongue, Sibawaih's analysis of Arabic grammar was so thorough and precise that al-Kitab remains the foundational reference in Arabic linguistics to this day.\n\nBorn in the Persian town of Bayda, Sibawaih came to Basra to study hadith but found his Arabic insufficient and turned to the study of grammar. He studied under al-Khalil ibn Ahmad al-Farahidi, from whom he absorbed the theoretical foundations of Arabic grammatical analysis. His work systematically described Arabic syntax, morphology, and phonology with unprecedented rigor.\n\nAl-Kitab contains over 1,000 Quranic citations and thousands of examples from pre-Islamic poetry, making it both a grammar and a literary treasury. After Sibawaih's early death in Shiraz at around thirty-six years of age, his work was transmitted by his students and became the central text of the Basran school of Arabic grammar. Later grammarians would either build upon or argue against his positions, but all worked within the framework he established.",

    144: "Harun ar-Rashid (766-809 CE) was the fifth Abbasid caliph whose reign is often considered the zenith of the Abbasid golden age. He presided over an empire that stretched from North Africa to Central Asia, with Baghdad as its magnificent capital and intellectual center.\n\nHarun is most remembered for his patronage of learning and scholars. He is credited with expanding the Bayt al-Hikmah (House of Wisdom) in Baghdad, which became the greatest center of scholarship in the medieval world, sponsoring the translation of Greek, Persian, and Indian scientific and philosophical works into Arabic. His court attracted poets, scholars, musicians, and scientists from across the known world.\n\nHis reign was also marked by diplomatic exchanges with Charlemagne, military campaigns against the Byzantine Empire, and the legendary wealth and splendor that inspired the tales of the Thousand and One Nights. However, he also made consequential political decisions, including the destruction of the Barmakid family who had served as his viziers. He died in Tus, Khurasan, while on a military campaign and was succeeded by his sons al-Amin and al-Mamun, whose rivalry would plunge the caliphate into civil war.",

    145: "Imam Muhammad ibn Idris ash-Shafii (767-820 CE) was the founder of the Shafii school of jurisprudence and the pioneer of usul al-fiqh (principles of Islamic jurisprudence). His book ar-Risalah was the first systematic work on Islamic legal theory, establishing the methodology for deriving legal rulings from the primary sources.\n\nBorn in Gaza and raised in Mecca, ash-Shafii studied under Imam Malik in Medina and Muhammad ash-Shaybani in Baghdad, uniquely positioning him to synthesize the Medinan and Iraqi legal traditions. He developed a comprehensive legal methodology that balanced the authority of hadith with the tools of legal reasoning, providing a middle ground between the text-focused approach of the Medinans and the reason-focused approach of the Iraqis.\n\nAsh-Shafii spent his final years in Egypt, where he revised many of his earlier opinions, producing what scholars call his 'new school' (al-jadid). He was known for his eloquence, his sharp debating skills, and his mastery of Arabic language and poetry. He died in Cairo and his mosque and tomb remain important landmarks. The Shafii school is followed today in East Africa, Southeast Asia, southern Egypt, Yemen, and the Kurdish regions.",

    146: "Ibn Abi Shaybah (775-849 CE), fully Abu Bakr Abdullah ibn Muhammad ibn Abi Shaybah, was one of the great hadith scholars of the classical period and the compiler of al-Musannaf, one of the largest early hadith compilations. His al-Musannaf is organized by legal topics and contains not only prophetic hadith but also the opinions and practices of the companions and Tabiin (athar).\n\nIbn Abi Shaybah studied under some of the leading scholars of his time, including Waki ibn al-Jarrah, Sufyan ibn Uyaynah, and Abu Muawiyah. His compilation is particularly valuable because it preserves early legal discussions and companion opinions that provide insight into how Islamic law was practiced in the first generations.\n\nHis students included Imam al-Bukhari, Imam Muslim, and Abu Dawud, making him a critical link in the chain of hadith transmission. He was based in Kufa and was known for his extraordinary memory and his meticulous approach to hadith collection. His brother Uthman ibn Abi Shaybah was also a prominent hadith scholar.",

    147: "Yahya ibn Main (775-847 CE) was one of the greatest hadith critics in Islamic history and a pioneer of the science of narrator evaluation (ilm ar-rijal). Based in Baghdad, he devoted his life and his family's considerable wealth to collecting, verifying, and evaluating hadith.\n\nIbn Main traveled extensively in search of hadith and reportedly spent over a million dirhams of his inheritance on acquiring and verifying narrations. He studied under over a thousand scholars and developed an encyclopedic knowledge of hadith narrators, their backgrounds, their reliability, and their specific strengths and weaknesses. His pronouncements on narrator reliability became definitive references for subsequent hadith scholars.\n\nHis methodology was rigorous but fair. Unlike some critics who were considered overly harsh or overly lenient, Ibn Main was recognized for his balanced and well-informed judgments. Ahmad ibn Hanbal called him 'the most knowledgeable of us regarding the defects of hadith.' He died while performing Hajj in Medina, and his funeral prayer was attended by an enormous crowd. His legacy in hadith criticism remains foundational to this day.",

    148: "Ali ibn al-Madini (778-849 CE) was one of the foremost experts in hadith science, particularly in the study of hadith chains (isnad) and the identification of hidden defects (ilal) in narrations. He was the primary teacher of Imam al-Bukhari in hadith criticism, and al-Bukhari said, 'I never felt small in the presence of anyone except Ali ibn al-Madini.'\n\nIbn al-Madini developed the science of hadith criticism to an unprecedented level of sophistication. He analyzed the interconnections between narrators, identified common errors in transmission chains, and established principles for evaluating the reliability of complex narration networks. His book al-Ilal (The Hidden Defects) was a landmark contribution to hadith methodology.\n\nHe studied under hundreds of scholars, including Sufyan ibn Uyaynah, Abdurrahman ibn Mahdi, and Yahya ibn Said al-Qattan. His knowledge of narrator biographies was so comprehensive that even Yahya ibn Main, the other great critic of the age, would defer to his expertise on certain matters. He died in Samarra and is remembered as one of the most important scholars behind the methodology used to compile the authentic hadith collections.",

    149: "Ahmad ibn Hanbal (780-855 CE) was the founder of the Hanbali school of jurisprudence, the compiler of the Musnad (one of the largest hadith collections containing over 28,000 narrations), and one of the most revered figures in Sunni Islam. Born in Baghdad, he traveled extensively in search of hadith, studying under hundreds of scholars across the Muslim world.\n\nAhmad is most famous for his steadfastness during the Mihna (inquisition), when the Abbasid caliph al-Mamun imposed the Mutazili doctrine that the Quran was created. While other scholars capitulated under pressure, Ahmad refused to affirm this belief and was imprisoned, beaten, and tortured for over two years. His resistance became a defining moment in Sunni Islamic identity and earned him the title Imam Ahl as-Sunnah (the Imam of the People of the Sunnah).\n\nAhmad's juristic methodology gave primacy to the Quran, Sunnah, companion opinions, and weak hadith over analogical reasoning. His students compiled his legal opinions into the Hanbali school of law. He died in Baghdad and his funeral was attended by hundreds of thousands of people. The Hanbali school is followed primarily in Saudi Arabia and Qatar, and his theological legacy influenced later reformers like Ibn Taymiyyah and Muhammad ibn Abdul-Wahhab.",

    150: "Ahmad ibn Abi al-Hawari (780-860 CE) was a prominent early ascetic and spiritual figure based in Damascus. He was a devoted student of Abu Sulayman ad-Darani, one of the greatest early Sufi masters, and he transmitted many of his teacher's spiritual insights to later generations.\n\nIbn Abi al-Hawari was known for his intense devotion to worship, his renunciation of worldly comforts, and his constant remembrance of Allah. His sayings on the spiritual life were recorded and transmitted, contributing to the growing body of literature on Islamic asceticism and inward purification that characterized the early Sufi tradition.\n\nDespite his ascetic orientation, he remained grounded in the Shariah and was careful to base his spiritual practice on the Quran and Sunnah. He lived in Damascus throughout his life and was revered by the people of the city for his piety and his gentleness. His contribution lies primarily in preserving and transmitting the spiritual teachings of the early Damascus school of asceticism.",

    151: "Al-Khwarizmi (c. 780-850 CE), fully Muhammad ibn Musa al-Khwarizmi, was a Persian Muslim mathematician and astronomer whose contributions fundamentally shaped mathematics as we know it. Working at the Bayt al-Hikmah (House of Wisdom) in Baghdad, he authored works that introduced revolutionary concepts to the world of mathematics.\n\nHis most famous work, al-Kitab al-Mukhtasar fi Hisab al-Jabr wal-Muqabalah, gave the world the field of algebra (from al-jabr in the title). This work systematically solved linear and quadratic equations using both algebraic and geometric methods. His name, Latinized as 'Algoritmi,' gave us the word 'algorithm,' reflecting his development of step-by-step computational procedures.\n\nAl-Khwarizmi also played a crucial role in introducing the Hindu-Arabic numeral system (including the concept of zero) to the Islamic world and subsequently to Europe. His astronomical tables and his work on geography, including a revision of Ptolemy's maps, made lasting contributions to those fields as well. He represents the best of the Islamic golden age: a scholar who synthesized knowledge from diverse civilizations and advanced it for all of humanity.",

    152: "Imam Ahmad ibn Hanbal (780-855 CE) was the founder of the Hanbali school of jurisprudence and compiler of the Musnad, which contains over 28,000 hadith. He is universally honored for his steadfastness during the Mihna (inquisition) when he refused to accept that the Quran was created, enduring imprisonment and torture rather than compromising his beliefs.\n\nHis legal methodology prioritized authentic hadith over analogical reasoning, and he was reluctant to issue legal opinions without direct textual support. He preferred even a weak hadith over personal opinion (ray) when no authentic narration was available on a topic. His approach influenced the development of a text-centered methodology in Islamic jurisprudence.\n\nAhmad's Musnad is organized by narrator rather than by legal topic, preserving the hadith of each companion together. He studied under hundreds of scholars, most notably ash-Shafii, Waki ibn al-Jarrah, and Sufyan ibn Uyaynah. His funeral in Baghdad drew an estimated 800,000 people, making it one of the largest gatherings in medieval history. His theological legacy, emphasizing adherence to the apparent meanings of the Quran and Sunnah, became the foundation of the Athari creed.",

    153: "Ibn Sad (784-845 CE), fully Muhammad ibn Sad al-Baghdadi, was a historian and hadith scholar who compiled at-Tabaqat al-Kubra (The Great Generations), the first major biographical dictionary of the companions of the Prophet and their successors. He was a student of the famous historian al-Waqidi.\n\nAt-Tabaqat organizes its biographical entries by generation (tabaqah), beginning with the Prophet himself, then the companions arranged by their chronological acceptance of Islam and by region, followed by the Tabiin and subsequent generations. The work provides detailed information about thousands of individuals: their lineage, their conversion stories, their hadith narrations, their character, and the circumstances of their deaths.\n\nIbn Sad's work is indispensable for the study of early Islamic history and for the science of narrator criticism. His biographical information about hadith narrators is frequently cited in the works of later hadith critics. He died in Baghdad and his Tabaqat remains one of the most important primary sources for understanding the first three generations of Muslims.",

    154: "Ad-Darimi (797-869 CE), fully Abdullah ibn Abdurrahman ad-Darimi, was a prominent hadith scholar from Samarkand who compiled the Musnad ad-Darimi, commonly known as Sunan ad-Darimi. This collection is considered one of the important early hadith compilations, sometimes mentioned alongside the six canonical collections.\n\nAd-Darimi traveled extensively in search of hadith, studying in the Hijaz, Syria, Egypt, Iraq, and Khurasan. His teachers included Yahya ibn Main, Ahmad ibn Hanbal, and other leading scholars of his generation. He was known for his prodigious memory and his mastery of hadith criticism.\n\nHis collection is notable for its arrangement by legal topics and its inclusion of both prophetic hadith and companion opinions. His students included the compilers of three of the six canonical collections: Imam Muslim, Imam at-Tirmidhi, and Abu Dawud, making him a crucial link in the transmission of hadith. He died in Samarkand and was mourned as one of the great scholars of Central Asia.",

    155: "Abdullah ad-Darimi (797-869 CE), fully Abdullah ibn Abdurrahman ad-Darimi, was a hadith scholar from Samarkand who compiled the Musnad ad-Darimi. He was a teacher of Imam Muslim, at-Tirmidhi, and Abu Dawud, three of the six canonical hadith compilers.\n\nAd-Darimi traveled across the Muslim world for decades collecting hadith, studying under Ahmad ibn Hanbal, Yahya ibn Main, and other major scholars. He was known for his strictness in accepting narrations and his comprehensive knowledge of hadith chains and narrators.\n\nHis compilation, the Sunan ad-Darimi, contains approximately 3,500 narrations organized by legal topics. While it is not counted among the six canonical collections, it is highly regarded for its reliability and is often studied alongside them. He returned to Samarkand after his years of travel and served as a teacher there until his death, making Central Asia an important node in the network of hadith transmission.",

    156: "Imam al-Bukhari (810-870 CE), fully Muhammad ibn Ismail al-Bukhari, compiled Sahih al-Bukhari, universally regarded as the most authentic book after the Quran. Born in Bukhara (in modern Uzbekistan), he showed extraordinary intellectual abilities from childhood, memorizing thousands of hadith by the age of sixteen.\n\nAl-Bukhari spent sixteen years compiling his Sahih, selecting approximately 7,275 hadith (including repetitions) from over 600,000 narrations. He applied the strictest criteria ever used for hadith authentication, requiring that each narrator in a chain must have met the one he narrated from and must be of the highest reliability. He would perform two units of prayer before including any hadith in his collection.\n\nHe traveled extensively across the Muslim world, studying under over 1,000 scholars. His other works include al-Adab al-Mufrad on Islamic manners, at-Tarikh al-Kabir (a biographical dictionary of hadith narrators), and several other hadith-related texts. He faced political persecution in his later years and died in Khartank, a village near Samarkand. His Sahih has been the subject of more commentaries than perhaps any other Islamic text after the Quran.",

    157: "Imam Muhammad al-Bukhari (810-870 CE) compiled Sahih al-Bukhari, the most authentic collection of hadith. He selected 7,275 hadith from over 600,000 narrations over sixteen years of meticulous work, applying the most rigorous standards of authentication ever employed in hadith scholarship.\n\nBorn in Bukhara, al-Bukhari was a prodigy who began attending hadith sessions as a child and quickly surpassed his teachers in memory and analytical ability. He traveled to all the major centers of Islamic learning, studying under scholars like Ali ibn al-Madini, Ahmad ibn Hanbal, and Yahya ibn Main. His mastery of hadith narrator biographies and his ability to identify defects in narration chains were legendary.\n\nHis Sahih is organized by legal and thematic topics, with al-Bukhari's own chapter headings revealing his legal acumen and theological positions. He also authored al-Adab al-Mufrad, a collection of hadith on Islamic ethics and manners, and at-Tarikh al-Kabir, a monumental biographical dictionary. He died in Khartank near Samarkand, and his legacy as the greatest hadith scholar in history is undisputed.",

    158: "Abu Dawud as-Sijistani (817-889 CE) compiled Sunan Abu Dawud, one of the six canonical hadith collections, which is particularly focused on hadith related to Islamic jurisprudence and legal rulings. He selected approximately 4,800 hadith from a collection of 500,000 narrations.\n\nBorn in Sistan (in modern Iran/Afghanistan), Abu Dawud traveled extensively in search of hadith, studying under Ahmad ibn Hanbal, Yahya ibn Main, and many other leading scholars. His collection was designed to be a comprehensive reference for jurists, containing all the hadith that formed the basis of Islamic legal rulings.\n\nAbu Dawud wrote a letter to the people of Mecca explaining his methodology and the principles behind his selection of hadith, which has been preserved and provides valuable insight into early hadith compilation methodology. He settled in Basra at the request of the governor and taught there until his death. Ahmad ibn Hanbal praised his work, and the Sunan Abu Dawud is considered one of the most important references for Islamic jurisprudence.",

    159: "Imam Muslim (821-875 CE), fully Muslim ibn al-Hajjaj an-Naysaburi, compiled Sahih Muslim, the second most authentic hadith collection after Sahih al-Bukhari. Born in Nishapur (in modern Iran), he traveled across the Muslim world studying under leading hadith scholars of his generation.\n\nMuslim spent approximately fifteen years compiling his Sahih, selecting about 7,500 hadith (with repetitions) from 300,000 narrations. His methodology differed slightly from al-Bukhari's in that he organized variant narrations of the same hadith together, making his work particularly useful for comparing different transmission chains. Many scholars consider his arrangement more systematic than al-Bukhari's.\n\nHe was a devoted student of al-Bukhari and considered him his teacher, though he also studied under Ahmad ibn Hanbal, Yahya ibn Main, and many others. His introduction to the Sahih contains an important discussion of hadith methodology that became a foundational text for the science of hadith criticism. He died in Nishapur and his Sahih has been the subject of numerous commentaries, most notably that of Imam an-Nawawi.",

    160: "Imam Muslim ibn al-Hajjaj (821-875 CE) compiled Sahih Muslim, the second most authentic collection of hadith after Sahih al-Bukhari. A student of Imam al-Bukhari, he developed his own rigorous methodology for authenticating hadith while benefiting from his teacher's expertise in narrator evaluation.\n\nMuslim's arrangement of hadith is often praised for its systematic organization: he groups all variant narrations of a single hadith together in one place, allowing the reader to compare different wordings and transmission chains. This approach makes Sahih Muslim particularly useful for hadith students and researchers.\n\nBorn and died in Nishapur, Muslim traveled widely in search of knowledge. His Sahih contains approximately 7,500 narrations and is considered the finest single-authored hadith collection in terms of its internal organization. Imam an-Nawawi's commentary on Sahih Muslim is one of the most widely studied works in the hadith tradition, and together the two Sahihs form the gold standard of hadith authentication.",

    161: "Imam at-Tirmidhi (824-892 CE), fully Muhammad ibn Isa at-Tirmidhi, compiled Jami at-Tirmidhi (also called Sunan at-Tirmidhi), one of the six canonical hadith collections. His work is unique among the six for including scholarly evaluations and juristic discussions alongside each hadith.\n\nAt-Tirmidhi studied under al-Bukhari and was deeply influenced by his methodology. For each hadith, he typically noted its grade of authenticity, mentioned which scholars accepted or rejected it, and discussed how different schools of jurisprudence ruled on the legal issue at hand. This approach made his collection an invaluable reference for understanding both hadith science and comparative fiqh.\n\nHe was born in Termez (in modern Uzbekistan) and lost his eyesight in his later years. Despite his blindness, he continued teaching and dictating hadith from his prodigious memory. His collection also includes a chapter on the physical description of the Prophet (ash-Shamail al-Muhammadiyyah), which became a beloved text studied separately. He died in Termez and is honored as one of the great scholars of Central Asia.",

    162: "Ibn Majah (824-887 CE), fully Muhammad ibn Yazid ibn Majah al-Qazwini, compiled Sunan Ibn Majah, the sixth of the canonical hadith collections. Born in Qazvin (in modern Iran), he traveled to Iraq, the Hijaz, Egypt, Syria, and other regions in search of hadith.\n\nHis Sunan contains approximately 4,341 hadith organized by legal topics. While the other five canonical collections were quickly accepted as authoritative, the inclusion of Ibn Majah's Sunan as the sixth book was debated by scholars, with some preferring the Sunan of ad-Darimi or the Muwatta of Malik for that position. Eventually, the scholarly consensus settled on Ibn Majah's work as the sixth.\n\nIbn Majah's collection includes some hadith not found in the other five collections, making it valuable for its unique material. However, hadith scholars have noted that his collection contains more weak narrations than the other five canonical works. He died in Qazvin and his Sunan has been the subject of commentaries and studies throughout Islamic history.",

    163: "Imam Abu Isa at-Tirmidhi (824-892 CE) compiled Jami at-Tirmidhi, notable for including scholarly evaluations and fiqh discussions with each hadith. A student of Imam al-Bukhari, he developed a distinctive approach to hadith compilation that blended authentication with juristic analysis.\n\nAt-Tirmidhi introduced grading terminology that enriched the vocabulary of hadith science. He used terms like hasan (good) to describe hadith that fell between the categories of sahih (authentic) and daif (weak), and he was among the first to systematically apply and explain these gradations to a wide audience.\n\nBorn in Termez, he traveled throughout the Muslim world before returning to his homeland where he continued teaching despite losing his sight. His ash-Shamail al-Muhammadiyyah, a collection of hadith describing the Prophet's appearance, habits, and character, became one of the most popular and widely-read hadith works in Islamic history. He died in Termez and his contributions to both hadith science and comparative fiqh remain indispensable.",

    164: "Al-Mubarrad (826-899 CE), fully Muhammad ibn Yazid al-Mubarrad, was the leading grammarian of the Basra school in his time and a major authority on Arabic language and literature. His most famous work, al-Kamil fil-Lughah wal-Adab (The Comprehensive in Language and Literature), is a masterful anthology of Arabic prose and poetry with grammatical and literary analysis.\n\nAl-Mubarrad served as the chief rival of Tha'lab, the leading grammarian of the Kufa school, and their scholarly debates in Baghdad were famous events that attracted large audiences. Their rivalry embodied the longstanding grammatical disagreements between the Basra and Kufa schools regarding Arabic linguistic theory.\n\nBased in Baghdad for most of his career, al-Mubarrad attracted students from across the Muslim world and produced several important works on Arabic grammar, rhetoric, and literary criticism. His analysis of Arabic poetry and prose set standards for literary criticism that influenced subsequent centuries. He died in Baghdad and is remembered as one of the last great representatives of the classical Basra grammatical tradition.",

    165: "Ibn Qutaybah (828-889 CE), fully Abu Muhammad Abdullah ibn Muslim ibn Qutaybah, was a polymath and prolific author based in Baghdad and Kufa whose works spanned Arabic literature, Quranic sciences, hadith interpretation, history, and natural philosophy.\n\nHis most enduring works include Adab al-Katib (The Secretary's Manual), a handbook for scribes that became a standard reference for Arabic writing; Ta'wil Mukhtalif al-Hadith (Reconciling Contradictory Hadith), which addressed apparent contradictions between hadith reports; and Ta'wil Mushkil al-Quran (Interpreting Difficult Quranic Passages), which tackled problematic Quranic passages from a linguistic and theological perspective.\n\nIbn Qutaybah was a defender of Sunni orthodoxy and traditional Arabic learning against the influence of Greek philosophy and Mutazili theology. His work Uyun al-Akhbar (The Choice Narratives) is a comprehensive anthology of Arabic prose organized by themes that became one of the most widely read works of adab (belles-lettres). He died in Baghdad and his works continue to be studied as classics of Arabic literary and intellectual heritage.",

    166: "Imam an-Nasai (829-915 CE), fully Ahmad ibn Shuayb an-Nasai, compiled Sunan an-Nasai, one of the six canonical hadith collections. His collection is notable for applying stricter authentication criteria than most of the other Sunan works, making it arguably the most rigorous collection after the two Sahihs.\n\nBorn in Nasa (in modern Turkmenistan), an-Nasai traveled widely across the Muslim world studying hadith. He initially compiled a larger collection called as-Sunan al-Kubra, which he then refined into the shorter as-Sunan as-Sughra (the Small Sunan), which is the version commonly referred to as Sunan an-Nasai. His critical methodology was praised by hadith scholars throughout history.\n\nAn-Nasai was also known for his personal piety and his devotion to worship. He would fast every other day and was known for his handsome appearance and dignified bearing. He died in Palestine (or Mecca, according to some accounts) and is honored as one of the great hadith masters whose work forms part of the canonical foundation of hadith literature.",

    167: "Imam Ahmad an-Nasai (829-915 CE) compiled Sunan an-Nasai, known for his strict grading criteria, making his collection arguably the most rigorous after the two Sahihs. His methodology in selecting and authenticating hadith was praised by scholars of his time and all subsequent generations.\n\nAn-Nasai originally compiled a larger work, as-Sunan al-Kubra, which contained a broader collection of hadith with varying degrees of authenticity. He then produced as-Sunan as-Sughra (also called al-Mujtaba), a refined selection containing only the strongest narrations. This abridged version is what is commonly studied and referred to as Sunan an-Nasai.\n\nBorn in Nasa, an-Nasai eventually settled in Egypt where he became the leading hadith scholar. In his later years, he traveled to Damascus, where he was asked about the merits of Muawiyah. His response, which acknowledged the merits of Ali, displeased some in the audience. According to some accounts, he was beaten and died as a result, making him a martyr for scholarly integrity.",

    168: "Junaid al-Baghdadi (830-910 CE) was one of the most important figures in the history of Islamic spirituality, known as Sayyid at-Taifah (the Master of the Group) and the leading exponent of 'sober' Sufism (as-sahw). His emphasis on grounding spiritual experience firmly within the Shariah made him a model for orthodox tasawwuf.\n\nJunaid was a student of several prominent early Sufis, including his uncle Sari as-Saqati and al-Harith al-Muhasibi. He was also a jurist trained in the Shafii school and insisted that spiritual practice must be built on a foundation of sound Islamic jurisprudence. He famously said, 'Our path is constrained by the Quran and Sunnah. Whoever does not memorize the Quran and write hadith and study fiqh is not to be followed.'\n\nHis theological and spiritual insights, expressed in letters, sayings, and recorded conversations, became foundational texts for later Sufi orders. His concept of fana (annihilation of the self in awareness of Allah) was carefully articulated to avoid pantheistic interpretations. He died in Baghdad and virtually every subsequent Sufi order traces its spiritual lineage through him.",

    169: "Ibn Hisham (d. 833 CE), fully Abu Muhammad Abdul-Malik ibn Hisham, was the editor and transmitter of the earliest biography of Prophet Muhammad, originally composed by Ibn Ishaq. His edited version, known as as-Sirah an-Nabawiyyah (The Prophetic Biography), became the standard text for studying the life of the Prophet.\n\nIbn Hisham was based in Egypt and received Ibn Ishaq's work through an intermediary. He edited the original by removing material he considered unrelated to the Prophet's life, correcting certain genealogies, and omitting poetry whose authenticity he questioned. He also added his own annotations and explanations throughout the text.\n\nAs-Sirah an-Nabawiyyah of Ibn Hisham is one of the most widely read and studied books in Islamic literature. It covers the Prophet's genealogy, his birth and early life, the beginning of revelation, the Meccan period, the migration to Medina, the major battles and events of the Medinan period, and the Prophet's death. Without Ibn Hisham's editorial work, Ibn Ishaq's pioneering biography might not have survived in an accessible form.",

    170: "Ibn Khuzaymah (837-924 CE), fully Muhammad ibn Ishaq ibn Khuzaymah, was a leading hadith scholar and Shafii jurist of Nishapur who was given the honorific title Imam al-Aimmah (the Imam of Imams) for his vast knowledge and authority. He compiled Sahih Ibn Khuzaymah, a hadith collection that aimed to include only authentic narrations.\n\nIbn Khuzaymah was known for his mastery of both hadith and fiqh, a combination that made his rulings particularly authoritative. He studied under the major hadith scholars of his generation and was the teacher of Ibn Hibban, who would compile his own Sahih. His Sahih Ibn Khuzaymah is particularly focused on hadith related to worship and was organized to demonstrate the legal implications of each narration.\n\nUnfortunately, only about a quarter of his Sahih has survived to the present day, the rest having been lost over the centuries. Even this partial survival, however, is an important source for hadith scholars. He spent his entire career in Nishapur, where he was the undisputed scholarly authority, and his death marked the end of an era for the city's hadith tradition.",

    171: "Imam at-Tabari (839-923 CE), fully Muhammad ibn Jarir at-Tabari, was one of the most prolific and important scholars in Islamic history, producing two monumental works that remain indispensable references: Jami al-Bayan an Ta'wil Ay al-Quran (the comprehensive tafsir) and Tarikh ar-Rusul wal-Muluk (the universal history).\n\nHis tafsir, commonly known as Tafsir at-Tabari, is the most comprehensive classical commentary on the Quran. For each verse, he collects and evaluates the interpretive opinions of the companions, the Tabiin, and the early scholars, then typically states which interpretation he considers strongest. This methodology established the standard for scholarly tafsir writing.\n\nHis Tarikh (History) is a universal chronicle beginning from creation and extending to his own time, providing year-by-year accounts of events in the Islamic world. At-Tabari was also a qualified mujtahid who developed his own school of jurisprudence (the Jariri school), which attracted followers but eventually disappeared. Born in Amol, Tabaristan, he spent most of his career in Baghdad, where he died after a life of extraordinary scholarly output.",

    172: "Imam Muhammad ibn Jarir at-Tabari (839-923 CE) authored the monumental Tafsir at-Tabari and Tarikh at-Tabari (History of Prophets and Kings). His tafsir is the most comprehensive classical commentary on the Quran, collecting and evaluating the interpretive opinions of early authorities for each verse.\n\nAt-Tabari's methodology in his tafsir was to present all the known interpretations of each verse with their chains of transmission, then to analyze and weigh them before stating his preferred view. This approach made his work not only a commentary but also a treasury of early Islamic exegetical traditions that might otherwise have been lost.\n\nHis historical work covers the entirety of human history from an Islamic perspective, from creation through the prophets and ancient civilizations to the events of the Islamic era. Both works are characterized by their comprehensiveness, their reliance on transmitted reports with full chains of narration, and their meticulous organization. Born in Amol and based in Baghdad, at-Tabari was also a qualified mujtahid who founded his own school of law, though it did not survive beyond a few generations.",

    173: "Imam at-Tahawi (843-933 CE), fully Ahmad ibn Muhammad at-Tahawi, was a major Hanafi jurist and hadith scholar of Egypt, best known as the author of al-Aqidah at-Tahawiyyah (The Tahawi Creed), which became the most widely accepted and concise summary of Sunni Islamic beliefs.\n\nAl-Aqidah at-Tahawiyyah presents the core beliefs of Ahl as-Sunnah wal-Jamaah in clear, straightforward language, covering the attributes of Allah, prophethood, the unseen, predestination, and other theological topics. Its authority lies in its careful adherence to the consensus of the early Muslim community and its avoidance of controversial philosophical speculation.\n\nAt-Tahawi originally studied under his uncle al-Muzani, a senior student of ash-Shafii, in the Shafii school before switching to the Hanafi school. He authored numerous works on Hanafi fiqh and hadith, including Sharh Maani al-Athar (Explanation of the Meanings of Narrations), which systematically presents the hadith evidence for Hanafi legal positions. He died in Cairo and his creedal text continues to be studied across the Muslim world as a primer on orthodox Sunni theology.",

    174: "Abu Mansur al-Maturidi (853-944 CE) was the founder of the Maturidi school of theology, one of the two major Sunni creedal schools (alongside the Ashari school). Born in Maturid near Samarkand, he developed a theological methodology that used rational arguments to defend the orthodox Sunni creed.\n\nAl-Maturidi's approach to theology differed from the Ashari school in several nuanced ways, including his greater emphasis on the role of reason in arriving at theological truths and his distinctive positions on divine attributes and human free will. His major theological work, Kitab at-Tawhid, provides a systematic defense of Sunni beliefs against the positions of the Mutazilah, the Jahmiyyah, and other theological groups.\n\nHe was also a Hanafi jurist and authored a tafsir known as Ta'wilat Ahl as-Sunnah, which interprets the Quran from a theological perspective. The Maturidi school of theology became the dominant creedal school among Hanafi Muslims, making it the theological school followed by the largest number of Muslims in the world, particularly in Turkey, Central Asia, and South Asia.",

    175: "Abu al-Qasim at-Tabarani (873-971 CE) was a prolific hadith collector who compiled three major encyclopedias of hadith: al-Mu'jam al-Kabir (The Great Dictionary), al-Mu'jam al-Awsat (The Middle Dictionary), and al-Mu'jam as-Saghir (The Small Dictionary). Together, these works contain tens of thousands of hadith narrations.\n\nAt-Tabarani was born in Tiberias, Palestine, and spent over sixty years of his life traveling across the Muslim world in search of hadith. He studied under over a thousand scholars and his collections preserve many narrations not found in the six canonical collections, making them invaluable for hadith researchers.\n\nHis al-Mu'jam al-Kabir is organized alphabetically by the names of companion narrators, making it an encyclopedic reference for hadith attributed to specific companions. He settled in Isfahan in his later years and continued teaching and dictating hadith until his death at the remarkable age of approximately one hundred. His collections are frequently cited in later hadith works as sources for supporting evidence and additional narrations.",

    176: "Abul-Hasan al-Ashari (874-936 CE), fully Ali ibn Ismail al-Ashari, was the founder of the Ashari school of theology, one of the two major Sunni creedal schools. He spent the first forty years of his life as a Mutazili theologian before dramatically abandoning their positions and returning to Sunni orthodoxy.\n\nAl-Ashari's conversion is one of the most famous events in Islamic intellectual history. He publicly announced his abandonment of Mutazili theology in the mosque of Basra, then devoted the rest of his life to defending the Sunni creed using the rational and philosophical tools he had mastered during his Mutazili years. His approach of using reason in the service of revelation became the hallmark of Ashari theology.\n\nHis major works include al-Ibanah an Usul ad-Diyanah (The Clarification of the Foundations of Religion) and Maqalat al-Islamiyyin (The Doctrines of the Muslims). The Ashari school, as developed by his successors al-Baqillani, al-Juwayni, and al-Ghazali, became the dominant theological school among Shafii and Maliki Muslims and remains so today across much of the Muslim world.",

    177: "Abu al-Hasan al-Ash'ari (874-936 CE) was the founder of the Ash'ari school of theology. Originally a Mu'tazili who studied under the leading Mu'tazili scholar al-Jubba'i, he underwent a dramatic conversion to Sunni orthodoxy and spent the remainder of his life defending traditional creed through rational argumentation.\n\nHis theological approach sought a middle path between the text-literalism of the Hanbalis and the rationalism of the Mu'tazilah. He affirmed the divine attributes mentioned in the Quran and Sunnah while using philosophical reasoning to defend these positions against Mu'tazili critiques. This methodology proved enormously influential and was developed further by generations of Ash'ari theologians.\n\nAl-Ash'ari's school eventually became the dominant theological framework across much of the Sunni Muslim world, adopted by the majority of Shafi'i and Maliki scholars. His integration of rational theology with scriptural fidelity provided an intellectual defense of Sunni Islam that continues to shape Muslim theological discourse. He died in Baghdad and his legacy is perpetuated through the Ash'ari tradition that bears his name.",

    178: "Ibn Hibban (884-965 CE), fully Muhammad ibn Hibban al-Busti, was a hadith scholar, historian, and geographer from Bust (in modern Afghanistan) who compiled Sahih Ibn Hibban, a major hadith collection organized uniquely by thematic and legal categories rather than the conventional chapter structure.\n\nIbn Hibban traveled extensively across the Muslim world in search of hadith and authored numerous works. His Sahih aimed to collect authentic hadith with a different organizational approach than al-Bukhari or Muslim, making some hadith easier to locate by topic. He also compiled ath-Thiqat (The Trustworthy Narrators), a major biographical dictionary of reliable hadith transmitters.\n\nHe was known for his broad learning, having authored works on history, geography, and medicine in addition to his hadith compilations. His geographical work in particular contains valuable information about the regions he visited. He served as a judge in Samarkand before settling in Bust, where he died. His Sahih, rearranged and edited by later scholars, remains an important supplementary source in hadith studies.",

    179: "Ad-Daraqutni (918-995 CE), fully Ali ibn Umar ad-Daraqutni, was one of the greatest hadith critics in Islamic history, renowned for his ability to identify the most subtle defects in hadith chains and texts. His expertise in the critical evaluation of hadith was considered unmatched in his era.\n\nAd-Daraqutni compiled several important works, including Sunan ad-Daraqutni, which focuses on hadith related to legal rulings, and al-Ilal (The Hidden Defects), which analyzes problematic hadith in exhaustive detail. He was also known for his critical notes on hadith found in Sahih al-Bukhari and Sahih Muslim, demonstrating that his analytical skills could be applied even to the most authenticated collections.\n\nBased in Baghdad, ad-Daraqutni was the leading hadith authority of the tenth century. His judgments on narrator reliability and hadith authenticity are frequently cited in later works of hadith criticism. He was also known for his knowledge of Quranic recitations (qiraat) and authored works in that field as well. He died in Baghdad and is regarded as one of the last great hadith critics of the classical era.",

    180: "Al-Khattabi (931-998 CE), fully Hamd ibn Muhammad al-Khattabi, was a Shafii scholar and hadith commentator best known for his work Maalim as-Sunan, one of the earliest and most important commentaries on Sunan Abu Dawud. He also authored Alam al-Hadith, a commentary on Sahih al-Bukhari.\n\nBorn in Bust (modern Afghanistan), al-Khattabi studied under scholars in Nishapur, Baghdad, and other major centers of learning. His commentaries are distinguished by their focus on explaining the legal implications of hadith and clarifying difficult Arabic terminology. His approach combined linguistic analysis with juristic reasoning.\n\nAl-Khattabi was also a literary figure who authored works on Arabic rhetoric and the inimitability of the Quran (ijaz al-Quran). His work Bayan Ijaz al-Quran argues for the miraculous nature of the Quran's literary style. He returned to Bust in his later years and died there. His commentaries on the hadith collections remain important references for students of hadith and fiqh.",

    181: "Al-Hakim an-Naysaburi (933-1014 CE), fully Muhammad ibn Abdullah al-Hakim, was a hadith scholar from Nishapur who compiled al-Mustadrak ala as-Sahihayn (The Supplement to the Two Sahihs), a collection of hadith that he believed met the authentication criteria of al-Bukhari and Muslim but were not included in their collections.\n\nAl-Hakim studied under approximately 2,000 scholars and was the leading hadith authority of Nishapur in his time. His Mustadrak contains over 8,000 hadith, though later scholars, particularly adh-Dhahabi, noted that al-Hakim was sometimes too lenient in his authentication and that many of the hadith did not actually meet the criteria of the two Sahihs.\n\nHe also authored Maarifat Ulum al-Hadith (Knowledge of Hadith Sciences), an important work on hadith methodology that classifies and explains the various types and categories of hadith. He died in Nishapur and his Mustadrak, despite the scholarly discussions about its authentication standards, remains a frequently consulted source for hadith that are not found in the two Sahihs.",

    182: "Abu Bakr ibn Furak (941-1015 CE) was a leading Ash'ari theologian and Shafi'i jurist based in Nishapur. He compiled the most comprehensive record of al-Ash'ari's theological positions in his work Mujarrad Maqalat al-Ash'ari, making him an essential source for understanding the founder's actual views.\n\nIbn Furak was known for his mastery of both theological reasoning and textual scholarship. He studied under prominent Ash'ari scholars in Baghdad and Isfahan before settling in Nishapur, where he became one of the leading religious authorities. His teaching attracted students from across the Muslim world.\n\nHe authored numerous works on theology, Quranic exegesis, and comparative religion. His death was reportedly due to poisoning, possibly orchestrated by theological opponents. Despite the tragic circumstances of his death, his intellectual legacy lived on through his students and his writings, which preserved and systematized Ash'ari theology during a critical period in its development.",

    183: "Abu Nu'aym al-Isfahani (948-1038 CE) was a hadith scholar and historian from Isfahan who authored Hilyat al-Awliya wa Tabaqat al-Asfiya (The Adornment of the Saints and the Generations of the Pure), a monumental biographical encyclopedia of pious Muslims from the companions through the early Sufi masters.\n\nThe Hilyat is a massive work of ten volumes that combines biographical information with hadith narrations, spiritual sayings, and accounts of the worship practices and miracles attributed to each figure. It covers the companions, the Tabiin, and the early ascetics and Sufis, providing a comprehensive record of Islamic piety and spirituality in the first centuries.\n\nAbu Nu'aym also compiled Dala'il an-Nubuwwah (Proofs of Prophethood), a work on the miracles and signs of Prophet Muhammad, and al-Mustakhraj ala Sahih Muslim, which traces alternative chains for the hadith in Sahih Muslim. He was one of the last scholars to hold the unbroken chains of narration going back to the earliest hadith collectors. He died in Isfahan at approximately ninety years of age.",

    184: "Abu Bakr al-Baqillani (950-1013 CE) was the foremost systematizer of Ash'ari theology and one of the most brilliant Muslim thinkers of the medieval period. His works transformed Ash'ari theology from a set of general principles into a comprehensive and rigorous theological system.\n\nAl-Baqillani's major work, Tamhid al-Awa'il wa Talkhis ad-Dala'il, provides a systematic exposition of Ash'ari beliefs with detailed philosophical arguments. He served as an ambassador for the Buyid rulers and was known for his sharp debating skills, reportedly defeating Christian and other scholars in formal theological disputes.\n\nHis work on the inimitability of the Quran (Ijaz al-Quran) is considered one of the most sophisticated treatments of the subject. He also made important contributions to Islamic political theory. Based in Baghdad, al-Baqillani followed the Maliki school of jurisprudence and combined his theological expertise with practical political engagement. His systematization of Ash'ari kalam influenced virtually all subsequent Ash'ari theologians.",

    185: "Abu Ishaq al-Isfarayini (950-1027 CE) was a prominent Ash'ari theologian and Shafi'i jurist of Nishapur. He was a contemporary of al-Baqillani and contributed significantly to the development of Ash'ari kalam (speculative theology) through his teaching and writing.\n\nAl-Isfarayini was based in Nishapur, where he and Abu Bakr ibn Furak represented the Ash'ari school in the intellectual life of the city. He was known for his rigorous approach to theology and his willingness to engage with the arguments of rival theological schools, including the Mu'tazilah and the Karramiyyah.\n\nHis students included some of the most important Ash'ari theologians of the next generation, ensuring that his contributions were transmitted and developed further. He died in Nishapur and is remembered as one of the key figures in the establishment of Ash'ari theology in eastern Iran, a region where it would later flourish through the works of al-Juwayni and al-Ghazali.",

    186: "Ibn Abdul-Barr (978-1071 CE), fully Yusuf ibn Abdullah ibn Abdul-Barr, was the leading Maliki scholar of al-Andalus and one of the greatest hadith scholars of the Muslim West. He authored two major works that remain indispensable references: at-Tamhid (a commentary on al-Muwatta organized by narrator chain) and al-Istiab fi Maarifat al-Ashab (a comprehensive dictionary of the Prophet's companions).\n\nIbn Abdul-Barr's at-Tamhid is considered one of the finest works of hadith commentary ever written, providing detailed discussions of legal issues, narrator biographies, and scholarly opinions for each hadith in al-Muwatta. His al-Istiab was the standard reference on companion biographies until Ibn Hajar al-Asqalani's al-Isabah superseded it.\n\nDespite being Maliki in jurisprudence, Ibn Abdul-Barr showed remarkable independence of thought and sometimes favored the positions of other schools when he found their evidence stronger. He was also known for his Zahiri sympathies in certain issues, reflecting the intellectual diversity of Andalusian scholarship. He died in Xativa, Spain, and his works continue to be studied throughout the Muslim world.",

    187: "Al-Bayhaqi (994-1066 CE), fully Ahmad ibn al-Husayn al-Bayhaqi, was a major Shafii hadith scholar and jurist who compiled as-Sunan al-Kubra (The Great Sunan), one of the largest and most comprehensive hadith compilations in Islamic history, containing over 21,000 narrations.\n\nBorn in Bayhaq (in modern Khorasan), al-Bayhaqi studied under al-Hakim an-Naysaburi and other leading scholars. His as-Sunan al-Kubra was designed to collect all the hadith evidence relevant to Islamic jurisprudence, organized by legal topics, making it an exhaustive reference for Shafii legal positions in particular.\n\nAl-Bayhaqi also authored numerous other works, including Shu'ab al-Iman (The Branches of Faith), Dala'il an-Nubuwwah (Proofs of Prophethood), and al-Asma was-Sifat (The Divine Names and Attributes). His prodigious output and his meticulous approach to hadith compilation earned him a place among the greatest hadith scholars in Islamic history. He died in Nishapur and his works remain essential references for hadith researchers and jurists.",

    188: "Ibn Hazm (994-1064 CE), fully Ali ibn Ahmad ibn Said ibn Hazm, was one of the most brilliant and controversial scholars of al-Andalus. He was the leading proponent of the Zahiri (literalist) school of jurisprudence in the Muslim West and one of the most prolific authors in Islamic history, reportedly writing over 400 works.\n\nIbn Hazm's legal methodology rejected analogical reasoning (qiyas) entirely, insisting instead on the apparent (zahir) meaning of the Quran and Sunnah. His magnum opus in fiqh, al-Muhalla bi'l-Athar, is a comprehensive legal encyclopedia that argues Zahiri positions with extraordinary erudition and forceful reasoning. He engaged in fierce polemics with scholars of other schools, earning both admiration for his brilliance and criticism for his sharp tongue.\n\nBeyond jurisprudence, Ibn Hazm authored works on logic, comparative religion (al-Fasl fi al-Milal), ethics, and even a celebrated treatise on love called Tawq al-Hamama (The Ring of the Dove). He was of Iberian convert stock and served briefly in political positions before devoting himself entirely to scholarship. He died near Huelva, Spain, and is regarded as one of the great independent thinkers of Islamic civilization.",

    189: "Al-Khatib al-Baghdadi (1002-1071 CE), fully Ahmad ibn Ali al-Khatib al-Baghdadi, was a Shafii hadith scholar and historian who made foundational contributions to both hadith methodology and Islamic historiography. His Tarikh Baghdad (History of Baghdad) is a monumental biographical dictionary covering the scholars, jurists, and notables of Baghdad.\n\nAl-Khatib authored numerous works on hadith sciences, including al-Kifayah fi Ilm ar-Riwayah (The Sufficiency in the Science of Narration) and al-Jami li-Akhlaq ar-Rawi wa Adab as-Sami (The Comprehensive on the Ethics of the Narrator and Listener). These works systematized the principles of hadith transmission and became standard references for hadith methodology.\n\nHe traveled extensively across the Muslim world, studying under scholars in Nishapur, Isfahan, the Hijaz, and other regions. His Tarikh Baghdad contains over 7,000 biographical entries and is an invaluable source for the intellectual history of medieval Baghdad. He died in Baghdad and his contributions to hadith methodology continue to form part of the standard curriculum in hadith studies.",

    190: "As-Sarakhsi (1009-1090 CE), fully Muhammad ibn Ahmad as-Sarakhsi, was a Hanafi jurist from Khurasan who authored al-Mabsut, a thirty-volume encyclopedia of Hanafi jurisprudence that is one of the most comprehensive legal works in Islamic history.\n\nRemarkably, as-Sarakhsi dictated much of al-Mabsut while imprisoned in a well or underground cell, where he had been confined for opposing the ruler on a legal issue. His students would gather at the opening of the well to receive his dictation. This extraordinary feat of scholarship under such adverse conditions is one of the most famous stories in the history of Islamic learning.\n\nAl-Mabsut is essentially a detailed commentary on the works of Muhammad ash-Shaybani, providing extensive discussions of Hanafi legal positions with their evidence, comparisons with other schools, and practical applications. It became one of the primary reference works for Hanafi jurists and continues to be consulted by scholars and courts in the Hanafi tradition. As-Sarakhsi also authored works on usul al-fiqh (legal theory), contributing to the development of Hanafi legal methodology.",

    191: "Al-Baghawi (1044-1122 CE), fully al-Husayn ibn Masud al-Baghawi, was a Shafii scholar from Baghshur (in modern Afghanistan) who earned the title Muhyi as-Sunnah (Reviver of the Sunnah) for his works that brought prophetic teachings to a wide audience. He was known for his mastery of tafsir, hadith, and fiqh.\n\nHis tafsir, Maalim at-Tanzil, became one of the most widely read and accessible Quranic commentaries. It presents the interpretive opinions of the early scholars in clear, straightforward language, making it suitable for both students and general readers. His hadith work, Sharh as-Sunnah, organizes and explains hadith by legal topics with useful juristic commentary.\n\nAl-Baghawi also compiled Masabih as-Sunnah, a collection of hadith organized by topic that was later expanded by al-Khatib at-Tibrizi into Mishkat al-Masabih, one of the most popular hadith anthologies in the Muslim world. His works are characterized by their clarity, reliability, and practical utility. He died in Marw ar-Rudh (in modern Turkmenistan) and his scholarly legacy continues to benefit students of Islam.",

    192: "Imam al-Ghazali (1058-1111 CE), fully Abu Hamid Muhammad al-Ghazali, was one of the most influential scholars in Islamic history, bearing the title Hujjat al-Islam (the Proof of Islam). His magnum opus, Ihya Ulum ad-Din (The Revival of the Religious Sciences), is one of the most comprehensive and widely read works on Islamic practice, ethics, and spirituality.\n\nAl-Ghazali served as the head professor at the prestigious Nizamiyyah academy in Baghdad at the age of thirty-three. At the height of his fame, he experienced a spiritual crisis that left him unable to eat or speak in public. He abandoned his position and spent years traveling, practicing asceticism, and seeking spiritual purification in Syria, Palestine, and the Hijaz before returning to teaching.\n\nHis works span virtually every Islamic discipline: theology (al-Iqtisad fi al-Itiqad), philosophy (Tahafut al-Falasifah, a devastating critique of Aristotelian philosophy), jurisprudence, Sufism, and education. His greatest achievement was his synthesis of orthodox Sunni theology, Shafii jurisprudence, and sober Sufism into a coherent whole, demonstrating that legal observance and spiritual development are complementary rather than contradictory. He died in Tus, Iran.",

    193: "Al-Zamakhshari (1075-1144 CE), fully Mahmud ibn Umar al-Zamakhshari, was a scholar from Khwarazm (modern Turkmenistan) who authored al-Kashshaf (The Revealer), a Quranic commentary celebrated for its unparalleled analysis of Arabic rhetoric, grammar, and literary style.\n\nAl-Kashshaf represents the pinnacle of linguistic Quranic exegesis. For each verse, al-Zamakhshari analyzes the rhetorical devices, grammatical structures, and subtle nuances of the Arabic text with extraordinary depth and precision. Despite al-Zamakhshari's known Mutazili theological leanings, which sometimes influenced his interpretive choices, his linguistic insights were so valuable that scholars from all theological backgrounds studied and commented on his work.\n\nAl-Zamakhshari was also a distinguished grammarian and lexicographer. His work Asas al-Balaghah is an important Arabic dictionary, and he authored several works on Arabic grammar and rhetoric. He traveled to Mecca, where he lived for extended periods, earning the title Jar Allah (neighbor of Allah's House). He died in Gurganj and his al-Kashshaf continues to be studied as an essential work of Quranic scholarship.",

    194: "Ibn al-Arabi al-Maliki (1076-1148 CE), fully Abu Bakr Muhammad ibn Abdullah ibn al-Arabi, was a Maliki judge and scholar from Seville, al-Andalus, who authored Ahkam al-Quran (Legal Rulings from the Quran), one of the most important works on deriving Islamic law from the Quran. He should not be confused with the Sufi thinker Muhyi ad-Din Ibn Arabi.\n\nIbn al-Arabi traveled from al-Andalus to the eastern Muslim world as a young man, studying under scholars in Baghdad, Damascus, and other cities. He studied under al-Ghazali and other prominent scholars before returning to Seville, where he served as a judge. His Ahkam al-Quran systematically identifies the legal content of the Quran and discusses the rulings derived from it according to different schools of jurisprudence, with particular emphasis on the Maliki perspective.\n\nHe also authored al-Awasim min al-Qawasim (Protection from Calamities), a defense of the companions of the Prophet against accusations regarding the early civil wars. His works demonstrate the high level of Maliki scholarship in al-Andalus during its final centuries. He died in Fez, Morocco, after being expelled from al-Andalus.",

    195: "Abdul-Qadir al-Jilani (1078-1166 CE) was a Hanbali scholar, preacher, and spiritual figure based in Baghdad whose sermons drew enormous crowds and whose spiritual influence extended across the Muslim world. He is revered by many Muslims as one of the greatest saints in Islamic history.\n\nBorn in Jilan (modern Gilan, Iran), Abdul-Qadir came to Baghdad as a young man to study. He mastered Hanbali jurisprudence and became an accomplished scholar before turning to a more ascetic and spiritual life. His sermons, collected in works like al-Fath ar-Rabbani (The Divine Opening) and Futuh al-Ghayb (Revelations of the Unseen), combined orthodox scholarship with powerful spiritual exhortation.\n\nHis teaching circle at his school in Baghdad grew so large that thousands of people would attend. He emphasized the importance of combining outward religious observance with inward spiritual purification. After his death, his followers established the Qadiriyyah Sufi order in his name, which became one of the most widespread Sufi brotherhoods in the world, with adherents across Africa, South Asia, Southeast Asia, and the Middle East.",

    196: "As-Samani (1113-1166 CE), fully Abdul-Karim ibn Muhammad as-Samani, was a Shafii hadith scholar and genealogist from Merv (in modern Turkmenistan) who compiled al-Ansab (The Lineages), a biographical dictionary that organizes scholars and notable figures by their nisbah (geographic, tribal, or professional attribution).\n\nAs-Samani traveled extensively across the Muslim world, visiting over 200 cities to collect biographical information and verify scholarly lineages. His al-Ansab is an invaluable resource for understanding the geographic and social origins of hadith narrators and scholars. The work provides not only biographical data but also descriptions of the cities and regions from which scholars came.\n\nHe was a descendant of a distinguished scholarly family and himself a master of hadith, having obtained some of the highest chains of narration in his time. His other works include Adab al-Imla wal-Istimla on hadith teaching methodology. He died in Merv and his al-Ansab was later summarized by Ibn al-Athir in al-Lubab fi Tahdhib al-Ansab.",

    197: "Ibn al-Jawzi (1116-1201 CE), fully Abdurrahman ibn Ali ibn al-Jawzi, was one of the most prolific scholars in Islamic history, a Hanbali jurist, preacher, and author reportedly credited with over 700 works. Based in Baghdad, he was the most famous preacher of his era, drawing tens of thousands to his gatherings.\n\nIbn al-Jawzi authored works in virtually every Islamic discipline: tafsir, hadith, fiqh, history, biography, asceticism, and preaching. His Zad al-Masir fi Ilm at-Tafsir is a comprehensive tafsir; his Talbis Iblis (The Devil's Deception) exposes innovations and deviations across different groups; and his Sifat as-Safwah is a biographical dictionary of pious Muslims. He was also a sharp critic of what he considered excessive Sufi practices.\n\nHis preaching sessions in Baghdad were legendary for their emotional power and intellectual depth. He was known for his wit, his eloquence, and his ability to move vast audiences to tears of repentance. He fell out of political favor late in life and was imprisoned for several years before being released. He died in Baghdad and is buried near the tomb of Ahmad ibn Hanbal.",

    198: "Ibn Rushd (1126-1198 CE), known in the West as Averroes, was an Andalusian Maliki jurist, philosopher, and physician from Cordoba who made profound contributions to both Islamic jurisprudence and Aristotelian philosophy. He served as the chief judge of Cordoba and as court physician to the Almohad caliphs.\n\nIn Islamic jurisprudence, his Bidayat al-Mujtahid wa Nihayat al-Muqtasid (The Distinguished Jurist's Primer) is a masterpiece of comparative fiqh that presents the legal opinions of the four Sunni schools on each topic, analyzes the evidence for each position, and identifies the source of their disagreements. This work remains one of the most useful introductions to Islamic comparative law.\n\nIn philosophy, Ibn Rushd wrote extensive commentaries on nearly all of Aristotle's works, earning him the title 'The Commentator' in medieval Europe. His philosophical works, particularly Tahafut at-Tahafut (The Incoherence of the Incoherence), a response to al-Ghazali's critique of philosophy, profoundly influenced both Islamic and European intellectual history. He was briefly exiled for his philosophical views but was eventually rehabilitated. He died in Marrakesh.",

    199: "Al-Marghinani (1135-1197 CE), fully Burhan ad-Din Ali al-Marghinani, was a Hanafi jurist from Marghinan (in modern Uzbekistan) who authored al-Hidayah fi Sharh Bidayat al-Mubtadi (The Guidance in Commentary on the Beginning for the Novice), which became the most widely studied and authoritative text of Hanafi jurisprudence.\n\nAl-Hidayah is a commentary on al-Marghinani's own abridged text, Bidayat al-Mubtadi, and provides detailed discussions of Hanafi legal positions with their evidence and rationale. The work masterfully balances comprehensiveness with accessibility, making it suitable for both advanced students and practicing jurists. It systematically presents the views of Abu Hanifah, Abu Yusuf, and Muhammad ash-Shaybani, identifying areas of agreement and disagreement.\n\nAl-Hidayah became the primary teaching text in Hanafi legal education across the Muslim world and has been the subject of numerous commentaries, supercommentaries, and translations. Courts operating under Hanafi law, including those of the Ottoman and Mughal empires, used it as a primary reference. Al-Marghinani spent over thirteen years composing the work, reportedly fasting the entire time. He died in Marghinan.",

    200: "Ibn Qudamah (1147-1223 CE), fully Muwaffaq ad-Din Abdullah ibn Ahmad ibn Qudamah al-Maqdisi, was the most important Hanbali jurist of his era and the author of al-Mughni, the definitive encyclopedia of Hanbali comparative jurisprudence. Born in Nablus, Palestine, he later settled in Damascus.\n\nAl-Mughni is a monumental work that presents the Hanbali legal positions alongside the opinions of other schools, providing a comprehensive comparative analysis with their respective evidence. It remains the most authoritative single reference for Hanbali fiqh and is widely consulted by scholars of all schools for its thorough presentation of legal arguments.\n\nIbn Qudamah also authored al-Umdah, a concise Hanbali fiqh primer; al-Kafi, an intermediate text; and al-Muqni, an advanced reference. He participated in Salah ad-Din's campaigns against the Crusaders and was known for combining scholarly excellence with practical engagement in the affairs of the Muslim community. He also wrote Lum'at al-Itiqad, a concise creedal text. He died in Damascus and his works form the backbone of Hanbali legal literature.",
}

def add_bios():
    with open(SCHOLARS_FILE, 'r', encoding='utf-8') as f:
        scholars = json.load(f)

    count = 0
    for i, scholar in enumerate(scholars):
        sid = scholar['id']
        if sid in BIOS and 'bio_en' not in scholar:
            new_scholar = {}
            inserted = False
            for key, value in scholar.items():
                new_scholar[key] = value
                if key == 'bio_short_en' and not inserted:
                    new_scholar['bio_en'] = BIOS[sid]
                    inserted = True
            if not inserted:
                new_scholar['bio_en'] = BIOS[sid]
            scholars[i] = new_scholar
            count += 1

    with open(SCHOLARS_FILE, 'w', encoding='utf-8') as f:
        json.dump(scholars, f, ensure_ascii=False, indent=2)
    with open(SCHOLARS_FILE, 'a', encoding='utf-8') as f:
        f.write('\n')

    print(f"Added bio_en to {count} scholars")

if __name__ == '__main__':
    add_bios()
